/* ─────────────────────────────────────────────
   NAVBAR
───────────────────────────────────────────── */
function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [open, setOpen] = useState(false);
  useEffect(() => {
    const h = () => setScrolled(window.scrollY > 60);
    window.addEventListener("scroll", h);
    return () => window.removeEventListener("scroll", h);
  }, []);
  const links = ["Services", "Parts", "Why Us", "Testimonials", "FAQ", "Contact"];
  return (
    <nav style={{ position: "fixed", top: 0, left: 0, right: 0, zIndex: 1000, background: scrolled ? "rgba(8,12,30,0.97)" : "rgba(8,12,30,0.72)", backdropFilter: "blur(16px)", borderBottom: scrolled ? "1px solid rgba(255,255,255,0.07)" : "none", transition: "background 0.4s" }}>
      <div style={{ maxWidth: 1280, margin: "0 auto", padding: "0 5%", display: "flex", alignItems: "center", justifyContent: "space-between", height: 84 }}>
        <a href="#" style={{ textDecoration: "none" }}><TecurLogo size={52} /></a>
        <div className="desk-nav" style={{ display: "flex", alignItems: "center", gap: 36 }}>
          {links.map(l => (
            <a key={l} href={`#${l.toLowerCase().replace(/\s/g, "")}`} style={{ color: C.silver, textDecoration: "none", fontFamily: "'Barlow Condensed', sans-serif", fontSize: 15, letterSpacing: 2, textTransform: "uppercase", fontWeight: 700, transition: "color 0.2s" }}
              onMouseEnter={e => e.target.style.color = C.red} onMouseLeave={e => e.target.style.color = C.silver}>{l}</a>
          ))}
          <a href="#contact" className="btn-red" style={{ padding: "12px 26px", fontSize: 14 }}>Book Now</a>
        </div>
        <button onClick={() => setOpen(!open)} className="mob-btn" style={{ display: "none", background: "none", border: "none", cursor: "pointer", flexDirection: "column", gap: 6, padding: 6 }}>
          {[0, 1, 2].map(i => (
            <span key={i} style={{ display: "block", width: 26, height: 2, background: "#fff", borderRadius: 2, transition: "transform 0.3s, opacity 0.3s", transform: open ? (i === 0 ? "rotate(45deg) translate(5px,6px)" : i === 2 ? "rotate(-45deg) translate(5px,-6px)" : "") : "", opacity: open && i === 1 ? 0 : 1 }} />
          ))}
        </button>
      </div>
      {open && (
        <div style={{ background: "rgba(8,12,30,0.99)", padding: "28px 5% 40px", display: "flex", flexDirection: "column", gap: 24 }}>
          {links.map(l => (
            <a key={l} href={`#${l.toLowerCase().replace(/\s/g, "")}`} onClick={() => setOpen(false)} style={{ color: C.silver, textDecoration: "none", fontFamily: "'Barlow Condensed', sans-serif", fontSize: 24, letterSpacing: 3, textTransform: "uppercase", fontWeight: 800 }}>{l}</a>
          ))}
          <a href="#contact" onClick={() => setOpen(false)} className="btn-red" style={{ textAlign: "center", marginTop: 8 }}>Book Now</a>
        </div>
      )}
    </nav>
  );
}

